/**
 * assetManifest.js
 *
 * The source of truth for all in-game assets. Every entry binds:
 *   - id, name
 *   - category: 'terrain' | 'nature' | 'props' | 'water' | 'buildings'
 *   - footprint: { w, d } in grid cells
 *   - kind: 'terrain' (replaces ground tile) | 'object' (sits on top)
 *   - filename: image file in /assets/, generated by the AI image model
 *   - sizeScale: visual occupation of the cell width (1.0 = fills cell,
 *                0.4 = a small prop, 0.85 = a large plant). Decoupled from
 *                footprint so tiny props (jars, buckets, pebbles) can sit
 *                on a 1×1 cell without ballooning to its full diameter.
 *   - noShadow: skip the renderer's projected cast shadow when the PNG
 *               already includes its own slab/grounding shadow.
 *   - fitCell: scale a high-resolution object image to the cell width without
 *              re-compositing it into a low-resolution tile canvas.
 *   - flatBase: the source PNG has no slab/base painted at the bottom — the
 *               bottom edge IS the prop's feet. Anchors the image's bottom
 *               at the cell's front corner instead of its centre row.
 *   - shadowStyle: 'cast' (default) projects the asset silhouette; 'contact'
 *                  draws a small grounding shadow directly below low props.
 *   - builder: procedural voxel fallback (used only if the PNG is missing
 *              from disk — keeps the editor functional during dev)
 */

import * as A from './assetDefinitions.js';

const T = (id, name, foot = { w: 1, d: 1 }) => ({
    id, name, category: 'terrain', footprint: foot, kind: 'terrain',
    filename: `${id}.png`, sizeScale: 1,
});
const O = (category, defaultScale = 1) =>
    (id, name, foot = { w: 1, d: 1 }, sizeScale = defaultScale) => ({
        id, name, category, footprint: foot, kind: 'object',
        filename: `${id}.png`, sizeScale,
    });
const N = O('nature', 0.85);
const P = O('props',  0.5);
const W = O('water',  0.85);
const B = O('buildings', 1);
const TO = O('terrain', 1);

